import type { NextProxy } from "next/server"
import { NextResponse } from "next/server"
import { AUTH_ROUTES, PROTECTED_ROUTES } from "@/modules/auth/routing/auth-routes"
import { hasSessionCookie } from "@/modules/auth/server/session-cookie"

export const proxy: NextProxy = (request) => {
  const pathname = request.nextUrl.pathname
  const isProtectedRoute = PROTECTED_ROUTES.some((route) => pathname.startsWith(route))
  const isAuthRoute = AUTH_ROUTES.some((route) => pathname.startsWith(route))
  const hasSession = hasSessionCookie(request.cookies)

  if (isProtectedRoute && !hasSession) {
    return NextResponse.redirect(new URL("/login", request.url))
  }

  if (isAuthRoute && hasSession) {
    return NextResponse.redirect(new URL("/app", request.url))
  }

  return NextResponse.next()
}

export const config = {
  matcher: ["/app/:path*", "/admin/:path*", "/login", "/signup"],
}

